// frontend/src/Events.jsx
import { useContext, useEffect, useMemo, useState } from "react";
import { AuthContext } from "./AuthContext";

export default function Events() {
    const { user } = useContext(AuthContext);
    const isAdmin = String(user?.role || "").toUpperCase() === "ADMIN";

    const [events, setEvents] = useState([]);
    const [q, setQ] = useState("");
    const [loading, setLoading] = useState(true);
    const [err, setErr] = useState("");

    // add modal
    const [showAdd, setShowAdd] = useState(false);
    const [form, setForm] = useState({
        title: "",
        content: "",
        location: "",
        startAt: "",
        endAt: ""
    });

    // edit modal
    const [showEdit, setShowEdit] = useState(false);
    const [editEvent, setEditEvent] = useState(null);

    // ---------------- LOAD EVENTS ----------------
    useEffect(() => {
        (async () => {
            try {
                setLoading(true);
                const res = await fetch("/api/events");
                if (!res.ok) throw new Error(`Failed to load events (${res.status})`);
                const data = await res.json();
                setEvents(Array.isArray(data) ? data : []);
                setErr("");
            } catch (e) {
                setErr(e.message || "Failed to load events");
            } finally {
                setLoading(false);
            }
        })();
    }, []);

    // ---------------- FILTER ----------------
    const filtered = useMemo(() => {
        const t = q.toLowerCase();
        return events.filter(ev =>
            (ev.title || "").toLowerCase().includes(t) ||
            (ev.content || "").toLowerCase().includes(t) ||
            (ev.location || "").toLowerCase().includes(t) ||
            String(ev.id).includes(t)
        );
    }, [events, q]);

    // ---------------- HELPERS ----------------
    const toISO = v => (v ? new Date(v).toISOString() : null);
    const toLocal = v => (v ? v.slice(0, 16) : "");

    // ---------------- CREATE ----------------
    const handleAddChange = e => {
        const { name, value } = e.target;
        setForm(prev => ({ ...prev, [name]: value }));
    };

    const createEvent = async e => {
        e.preventDefault();
        if (!isAdmin) return;

        if (!form.title.trim() || !form.content.trim()) {
            alert("Title and content are required");
            return;
        }

        const payload = {
            title: form.title.trim(),
            content: form.content.trim(),
            location: form.location || null,
            startAt: toISO(form.startAt),
            endAt: toISO(form.endAt)
        };

        try {
            const res = await fetch(`/api/events?requesterEmail=${encodeURIComponent(user.email)}`, {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload)
            });

            const body = await res.json();
            if (!res.ok) throw new Error(body.message || `Create failed (${res.status})`);

            setEvents(prev => [body, ...prev]);
            setShowAdd(false);
            setForm({ title: "", content: "", location: "", startAt: "", endAt: "" });
        } catch (e2) {
            alert(e2.message || "Create failed");
        }
    };

    // ---------------- EDIT ----------------
    const openEdit = ev => {
        if (!isAdmin) return;
        setEditEvent({
            id: ev.id,
            title: ev.title || "",
            content: ev.content || "",
            location: ev.location || "",
            startAt: toLocal(ev.startAt),
            endAt: toLocal(ev.endAt)
        });
        setShowEdit(true);
    };

    const handleEditChange = e => {
        const { name, value } = e.target;
        setEditEvent(prev => ({ ...prev, [name]: value }));
    };

    const saveEdit = async e => {
        e.preventDefault();
        if (!isAdmin || !editEvent) return;

        const payload = {
            title: editEvent.title.trim(),
            content: editEvent.content.trim(),
            location: editEvent.location || null,
            startAt: toISO(editEvent.startAt),
            endAt: toISO(editEvent.endAt)
        };

        try {
            const res = await fetch(`/api/events/${editEvent.id}?requesterEmail=${encodeURIComponent(user.email)}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload)
            });

            const body = await res.json();
            if (!res.ok) throw new Error(body.message || `Update failed (${res.status})`);

            setEvents(prev => prev.map(e => (e.id === body.id ? body : e)));
            setShowEdit(false);
            setEditEvent(null);
        } catch (e2) {
            alert(e2.message || "Update failed");
        }
    };

    // ---------------- DELETE ----------------
    const deleteEvent = async ev => {
        if (!isAdmin) return;
        if (!window.confirm(`Delete event "${ev.title}"?`)) return;

        try {
            const res = await fetch(`/api/events/${ev.id}?requesterEmail=${encodeURIComponent(user.email)}`, {
                method: "DELETE"
            });
            const body = await res.json().catch(() => ({}));
            if (!res.ok) throw new Error(body.message || `Delete failed (${res.status})`);
            setEvents(prev => prev.filter(e => e.id !== ev.id));
        } catch (e2) {
            alert(e2.message || "Delete failed");
        }
    };

    // ---------------- RENDER ----------------
    return (
        <div style={s.wrap}>
            <div style={s.header}>
                <h2>Events</h2>
                <div>
                    <input value={q} onChange={e => setQ(e.target.value)} placeholder="Search…" style={s.search} />
                    <a href="#/" style={s.backLink}>← Home</a>
                    {isAdmin && <button style={s.addBtn} onClick={() => setShowAdd(true)}>+ Add Event</button>}
                </div>
            </div>

            {loading && <p>Loading…</p>}
            {err && <p style={{ color: "red" }}>{err}</p>}

            {!loading && !err && (
                <div style={s.table}>
                    {filtered.map(ev => (
                        <div key={ev.id} style={s.row}>
                            <div style={{ width: 60 }}>{ev.id}</div>
                            <div style={{ flex: 2 }}>{ev.title}</div>
                            <div style={{ flex: 2 }}>
                                {ev.startAt ? new Date(ev.startAt).toLocaleString() : "-"}
                            </div>
                            <div style={{ flex: 2 }}>{ev.location || "-"}</div>
                            {isAdmin && (
                                <div style={{ width: 200, textAlign: "right" }}>
                                    <button style={s.editBtn} onClick={() => openEdit(ev)}>Edit</button>
                                    <button style={s.delBtn} onClick={() => deleteEvent(ev)}>Delete</button>
                                </div>
                            )}
                        </div>
                    ))}
                </div>
            )}

            {/* ADD MODAL */}
            {isAdmin && showAdd && (
                <div style={s.backdrop}>
                    <div style={s.modal}>
                        <h3>Add Event</h3>
                        <form onSubmit={createEvent} style={{ display: "grid", gap: 10 }}>
                            <input name="title" placeholder="Title" value={form.title} onChange={handleAddChange} required style={s.input} />
                            <textarea name="content" placeholder="Content" value={form.content} onChange={handleAddChange} rows={4} required style={s.textarea} />
                            <input name="location" placeholder="Location" value={form.location} onChange={handleAddChange} style={s.input} />
                            <input type="datetime-local" name="startAt" value={form.startAt} onChange={handleAddChange} style={s.input} />
                            <input type="datetime-local" name="endAt" value={form.endAt} onChange={handleAddChange} style={s.input} />
                            <div style={{ display: "flex", justifyContent: "flex-end", gap: 8 }}>
                                <button type="button" onClick={() => setShowAdd(false)} style={s.cancelBtn}>Cancel</button>
                                <button type="submit" style={s.saveBtn}>Create</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* EDIT MODAL */}
            {isAdmin && showEdit && editEvent && (
                <div style={s.backdrop}>
                    <div style={s.modal}>
                        <h3>Edit Event</h3>
                        <form onSubmit={saveEdit} style={{ display: "grid", gap: 10 }}>
                            <input name="title" value={editEvent.title} onChange={handleEditChange} required style={s.input} />
                            <textarea name="content" value={editEvent.content} onChange={handleEditChange} rows={4} required style={s.textarea} />
                            <input name="location" value={editEvent.location} onChange={handleEditChange} style={s.input} />
                            <input type="datetime-local" name="startAt" value={editEvent.startAt} onChange={handleEditChange} style={s.input} />
                            <input type="datetime-local" name="endAt" value={editEvent.endAt} onChange={handleEditChange} style={s.input} />
                            <div style={{ display: "flex", justifyContent: "flex-end", gap: 8 }}>
                                <button type="button" onClick={() => { setShowEdit(false); setEditEvent(null); }} style={s.cancelBtn}>Cancel</button>
                                <button type="submit" style={s.saveBtn}>Save</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}
        </div>
    );
}

// ---------------- STYLES ----------------
const s = {
    wrap: { padding: 20, maxWidth: 1100, margin: "0 auto" },
    header: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 },
    search: { padding: "6px 8px", border: "1px solid #ccc", borderRadius: 6, marginRight: 12 },
    backLink: { textDecoration: "none", border: "1px solid #ccc", padding: "6px 10px", borderRadius: 6, background: "#f8f8f8", color: "#333", marginLeft: 8 },
    addBtn: { padding: "6px 10px", background: "#0b57d0", color: "#fff", border: "none", borderRadius: 6 },

    table: { background: "#fff", border: "1px solid #ddd", borderRadius: 8 },
    row: { display: "flex", gap: 8, padding: "10px 8px", borderBottom: "1px solid #eee", alignItems: "center" },

    delBtn: { padding: "6px 10px", background: "#b00020", color: "#fff", border: "none", borderRadius: 6, marginLeft: 8 },
    editBtn: { padding: "6px 10px", background: "#0b57d0", color: "#fff", border: "none", borderRadius: 6 },

    backdrop: { position: "fixed", inset: 0, background: "rgba(0,0,0,0.35)", display: "flex", alignItems: "center", justifyContent: "center" },
    modal: { background: "#fff", padding: 20, borderRadius: 8, width: 520 },
    input: { padding: "8px 10px", border: "1px solid #ccc", borderRadius: 6 },
    textarea: { padding: "8px 10px", border: "1px solid #ccc", borderRadius: 6 },
    cancelBtn: { padding: "6px 10px", background: "#ccc", border: "none", borderRadius: 6 },
    saveBtn: { padding: "6px 10px", background: "#0b57d0", color: "#fff", border: "none", borderRadius: 6 }
};
